// NanoMDMUserCreateBulk is the builder for creating many NanoMDMUser entities in bulk.
type NanoMDMUserCreateBulk struct {
	config
	err      error
	builders []*NanoMDMUserCreate
	conflict []sql.ConflictOption
}

// Save creates the NanoMDMUser entities in the database.
func (nmucb *NanoMDMUserCreateBulk) Save(ctx context.Context) ([]*NanoMDMUser, error) {
	if nmucb.err != nil {
		return nil, nmucb.err
	}
	specs := make([]*sqlgraph.CreateSpec, len(nmucb.builders))
	nodes := make([]*NanoMDMUser, len(nmucb.builders))
	mutators := make([]Mutator, len(nmucb.builders))
	for i := range nmucb.builders {
		func(i int, root context.Context) {
			builder := nmucb.builders[i]
			var mut Mutator = MutateFunc(func(ctx context.Context, m Mutation) (Value, error) {
				mutation, ok := m.(*NanoMDMUserMutation)
				if !ok {
					return nil, fmt.Errorf("unexpected mutation type %T", m)
				}
				if err := builder.check(); err != nil {
					return nil, err
				}
				builder.mutation = mutation
				var err error
				nodes[i], specs[i] = builder.createSpec()
				if i < len(mutators)-1 {
					_, err = mutators[i+1].Mutate(root, nmucb.builders[i+1].mutation)
				} else {
					spec := &sqlgraph.BatchCreateSpec{Nodes: specs}
					spec.OnConflict = nmucb.conflict
					// Invoke the actual operation on the latest mutation in the chain.
					if err = sqlgraph.BatchCreate(ctx, nmucb.driver, spec); err != nil {
						if sqlgraph.IsConstraintError(err) {
							err = &ConstraintError{msg: err.Error(), wrap: err}
						}
					}
				}
				if err != nil {
					return nil, err
				}
				mutation.id = &nodes[i].ID
				if specs[i].ID.Value != nil {
					id := specs[i].ID.Value.(int64)
					nodes[i].ID = int(id)
				}
				mutation.done = true
				return nodes[i], nil
			})
			for i := len(builder.hooks) - 1; i >= 0; i-- {
				mut = builder.hooks[i](mut)
			}
			mutators[i] = mut
		}(i, ctx)
	}
	if len(mutators) > 0 {
		if _, err := mutators[0].Mutate(ctx, nmucb.builders[0].mutation); err != nil {
			return nil, err
		}
	}
	return nodes, nil
}

